    it("denies every call when limit is 0", () => {
      const limiter = createLimiter(0, 1000);
      expect(limiter.allow("k", 0)).toBe(false);
      expect(limiter.allow("k", 5000)).toBe(false);
    });

    it("records nothing when limit is 0", () => {
      const limiter = createLimiter(0, 1000);
      limiter.allow("k", 0);
      // Raising the limit is not possible on an existing limiter, but a fresh
      // limiter with the same key demonstrates no cross-contamination anyway.
      const permissive = createLimiter(1, 1000);
      expect(permissive.allow("k", 0)).toBe(true);
    });

    it("honors the documented default window of 60000ms", () => {
      const limiter = createLimiter(1); // windowMs defaults to 60000
      expect(limiter.allow("k", 0)).toBe(true);
      // Just inside the window -> still counts.
      expect(limiter.allow("k", 59999)).toBe(false);
      // Exactly one window later -> expired.
      expect(limiter.allow("k", 60000)).toBe(true);
    });

    it("handles a limit of 1 as a strict single-slot window", () => {
      const limiter = createLimiter(1, 10);
      expect(limiter.allow("k", 0)).toBe(true);
      expect(limiter.allow("k", 5)).toBe(false);
      expect(limiter.allow("k", 9)).toBe(false);
      expect(limiter.allow("k", 10)).toBe(true);
    });
  });

  describe("realistic sequence", () => {
    it("models a bursty client over a sliding window", () => {
      const limiter = createLimiter(3, 1000);
      const seq = [
        [0, true], // 1st in window
        [100, true], // 2nd
        [200, true], // 3rd -> full
        [300, false], // over limit
        [900, false], // still full (0,100,200 all within 1000)
        [1000, true], // t=0 expired (0 > 0 false) -> slot frees
        [1050, false], // 100,200,1000 fill it again
        [1100, true], // t=100 expired -> slot frees
      ];
      for (const [now, expected] of seq) {
        expect(limiter.allow("client", now)).toBe(expected);
      }
    });
  });
});
